const items = $input.all();
const count = items.length;

if (count === 0) {
  return [{ json: { total: 0, message: 'No emails found', would_trigger: 0 } }];
}

const RATECONS_LABEL = 'Label_8836114819563300518';

const emails = items.map(item => {
  const labels = item.json.labelIds || [];
  const starred = labels.includes('STARRED');
  const unread = labels.includes('UNREAD');
  const ratecon = labels.includes(RATECONS_LABEL);
  const has_attachment = item.json.binary ? Object.keys(item.json.binary).length > 0 : false;
  return {
    subject: item.json.headers?.subject || item.json.subject || 'No subject',
    from: item.json.headers?.from || item.json.from || 'Unknown',
    date: item.json.headers?.date || item.json.date || 'Unknown',
    starred,
    unread,
    ratecon,
    has_attachment,
    would_trigger: starred && unread && ratecon
  };
});

emails.sort((a, b) => new Date(b.date) - new Date(a.date));
emails.forEach((e, i) => e.index = i + 1);

const triggerCount = emails.filter(e => e.would_trigger).length;

return [{ json: {
  total: count,
  would_trigger: triggerCount,
  emails
}}];
